-- a3b00000-0000-4000-8000-000000000000 動画別3問クイズ + 既存コース末(a3b90000-0000-4000-8000-000000000000)を末尾へ  自動生成
UPDATE public.lessons SET sort_order=1 WHERE id='a3b10000-0000-4000-8000-000000000000';
UPDATE public.lessons SET sort_order=3 WHERE id='a3b20000-0000-4000-8000-000000000000';
UPDATE public.lessons SET sort_order=5 WHERE id='a3b30000-0000-4000-8000-000000000000';
UPDATE public.lessons SET sort_order=7 WHERE id='a3b40000-0000-4000-8000-000000000000';
UPDATE public.lessons SET sort_order=99 WHERE id='a3b90000-0000-4000-8000-000000000000';

ON CONFLICT (id) DO UPDATE SET course_id=EXCLUDED.course_id,title=EXCLUDED.title,content_type=EXCLUDED.content_type,estimated_minutes=EXCLUDED.estimated_minutes,sort_order=EXCLUDED.sort_order;

DELETE FROM public.quiz_questions WHERE lesson_id IN ('a3b10900-0000-4000-8000-000000000000','a3b20900-0000-4000-8000-000000000000','a3b30900-0000-4000-8000-000000000000','a3b40900-0000-4000-8000-000000000000');

