INSERT INTO public.lessons (id,course_id,title,content_type,url,file_path,article_content,estimated_minutes,sort_order) VALUES
  ('a3b10900-0000-4000-8000-000000000000','a3b00000-0000-4000-8000-000000000000','確認テスト ─ 大組織の運営','quiz',NULL,NULL,NULL,3,2),
  ('a3b20900-0000-4000-8000-000000000000','a3b00000-0000-4000-8000-000000000000','確認テスト ─ 組織再編・統合','quiz',NULL,NULL,NULL,3,4),
  ('a3b30900-0000-4000-8000-000000000000','a3b00000-0000-4000-8000-000000000000','確認テスト ─ ガバナンスの設計','quiz',NULL,NULL,NULL,3,6),
  ('a3b40900-0000-4000-8000-000000000000','a3b00000-0000-4000-8000-000000000000','確認テスト ─ 危機管理','quiz',NULL,NULL,NULL,3,8)
INSERT INTO public.quiz_questions (lesson_id,question,option_a,option_b,option_c,option_d,correct_option,sort_order) VALUES
('a3b10900-0000-4000-8000-000000000000','本文が示す大組織運営の本質は、次のどれか。','何を中央に集め、何を現場に渡すかを、意図して配分すること','できるだけ多くの権限を現場にすべて手放すこと','重要な判断はすべて中央が握り、末端まで同じ基準で揃えること','階層を厚く積み、判断が通る段数を増やすこと','A',0),
('a3b10900-0000-4000-8000-000000000000','本文が言う統制の「二つの顔」のうち、大組織に要るとされるのはどれか。','逸脱を許さず、越えれば罰する縛る線','報告で人を監視し、萎縮させる線','組織がばらばらに崩れないよう芯を通す、支える背骨','念のためのルールを次々に足していく仕組み','C',1),
('a3b10900-0000-4000-8000-000000000000','設計2「分権の線を、引く」で本文が挙げる、線を引く二つの軸はどれか。','人数の多さと、予算の大きさ','影響の範囲と、後戻りのしやすさ','経験年数と、役職の高さ','緊急度と、報告の頻度','B',2),
('a3b20900-0000-4000-8000-000000000000','本文が示す統合の本質は、次のどれか。','形を一つにすることではなく、二つの組織のあいだに信頼を架けること','組織図と決裁の線を、速やかにつなぎ直すこと','強いほうのやり方に、弱いほうを合わせること','両方の良いところを、すべて活かすこと','A',0),
('a3b20900-0000-4000-8000-000000000000','本文が対比する「混ぜる統合」と「接ぐ統合」の説明として正しいのはどれか。','混ぜる統合は両方の良さを残し、接ぐ統合は良さを平均化して消す','接ぐ統合は速く、混ぜる統合は遅い','混ぜる統合は一気にかき混ぜて速いが両方の良さが薄まり、接ぐ統合はつなぎ目を見ながら両方の良さを残せる','どちらも書類上で完了し、中身に違いはない','C',1),
('a3b20900-0000-4000-8000-000000000000','ステップ5「文化を、時間をかけて接ぐ」で本文が示すやり方はどれか。','「今日から、うちの文化はこうです」と号令をかける','両社の人を同じチームで一緒に働かせ、接触を通じて自然に学び合わせる','一年で一つの文化に統一する締め切りを設ける','どちらか一方の文化を消し、片方に寄せる','B',2),
('a3b30900-0000-4000-8000-000000000000','本文が示すガバナンスの本質は、次のどれか。','立派な規程を整え、会議体を定期的に開くこと','執行を、外の目で監督し、暴走を止め、正しさを支える仕組み','執行のミスを見つけて責め、あら探しをすること','監督と執行を同じ人に集め、判断を速めること','B',0),
('a3b30900-0000-4000-8000-000000000000','本文が区別する「監視」と「監督」の違いとして正しいのはどれか。','監視は未来を守り、監督は過去を責める','監視も監督も、過去の失敗を追及する点で同じである','監視は過去を責めるので執行は隠し、監督は未来を守るので執行は相談する','監督は形式的なやりとりで、監視は現場を深く見る','C',1),
('a3b30900-0000-4000-8000-000000000000','仕掛け3「外の目を、入れる」で本文が述べる、外の目の効用はどれか。','身内が当たり前と思っていることに問いを立て、見えない死角を見せる','会議の議題を増やし、報告の量を厚くする','執行と利害を共にし、話を早く進める','外部の人を形式的に座らせ、権威づけする','A',2),
('a3b40900-0000-4000-8000-000000000000','本文が示す危機管理の本質は、次のどれか。','危機が来たとき、その場でしっかり対応すること','有事に強い組織を、平時のうちに設計しておくこと','火が出てから、素早く消火する腕を磨くこと','危機のときの、リーダーの勇気を鍛えること','B',0),
('a3b40900-0000-4000-8000-000000000000','本文が挙げる「危機管理の三つの時間」はどれか。','平時(備える)・有事(動く)・事後(学ぶ)','予測・実行・評価','準備・対応・報告','想定・訓練・記録','A',1),
('a3b40900-0000-4000-8000-000000000000','備え3「初動の型を、組んでおく」で本文が示す初動のおおむねの順はどれか。','関係者に知らせる→人の安全を確保→事実をつかむ→拡大を止める','事実をつかむ→人の安全を確保→被害の拡大を止める→関係者に知らせる','評判を守る→事実をつかむ→拡大を止める→安全を確保','上司の指示を待つ→事実をつかむ→安全を確保→知らせる','B',2);
